// ============================================================
// HASH & BUILD PAYLOAD — Code node
// ============================================================
// Faz: parse string body (sendBeacon força text/plain), allowlist guard,
// SHA-256 puro JS de PII, normalização phone Meta (sem +).
//
// PEGADINHAS:
// 1. sendBeacon do GTM envia text/plain — body chega como STRING, precisa JSON.parse()
// 2. crypto.subtle e require('crypto') bloqueados em N8N Cloud sandbox — usar SHA-256 puro JS
// 3. Phone Meta = dígitos puros sem '+' (diferente Google Ads que usa E.164 com +)
// 4. client_user_agent vem do front (navigator.userAgent), NÃO do header user-agent
//    do request (proxies/CDN podem alterar)
// 5. Allowlist guard: descarta eventos não-canônicos antes de hashear (poupa CPU
//    + visibilidade no log de skips). Defense in depth caso trigger no GTM falhe.

// ====== CONFIG (ajustar por projeto) ======
const PIXEL_ID = 'PIXEL_ID_HERE';
const API_VERSION = 'v23.0';
const TEST_EVENT_CODE = ''; // Setar pra QA inicial (ex: 'TEST12345'), remover em produção
const ALLOWED_EVENTS = ['Lead', 'MQL', 'NOICP'];

// ====== SHA-256 PURO JS (sem deps, sem crypto.subtle) ======
function sha256(message) {
  if (message === undefined || message === null || message === '') return '';
  message = String(message).toLowerCase().trim();
  function utf8Encode(str) {
    const bytes = [];
    for (let i = 0; i < str.length; i++) {
      let c = str.charCodeAt(i);
      if (c < 0x80) bytes.push(c);
      else if (c < 0x800) bytes.push(0xc0 | (c >> 6), 0x80 | (c & 0x3f));
      else if (c < 0xd800 || c >= 0xe000) bytes.push(0xe0 | (c >> 12), 0x80 | ((c >> 6) & 0x3f), 0x80 | (c & 0x3f));
      else {
        i++;
        c = 0x10000 + (((c & 0x3ff) << 10) | (str.charCodeAt(i) & 0x3ff));
        bytes.push(0xf0 | (c >> 18), 0x80 | ((c >> 12) & 0x3f), 0x80 | ((c >> 6) & 0x3f), 0x80 | (c & 0x3f));
      }
    }
    return bytes;
  }
  function rotr(n, b) { return (n >>> b) | (n << (32 - b)); }
  const K = [0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2];
  const H = [0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19];
  const bytes = utf8Encode(message);
  const l = bytes.length;
  bytes.push(0x80);
  while (bytes.length % 64 !== 56) bytes.push(0);
  const bitLen = l * 8;
  for (let i = 7; i >= 0; i--) bytes.push((bitLen / Math.pow(2, i * 8)) & 0xff);
  for (let chunk = 0; chunk < bytes.length; chunk += 64) {
    const W = new Array(64);
    for (let i = 0; i < 16; i++) W[i] = (bytes[chunk + i*4] << 24) | (bytes[chunk + i*4+1] << 16) | (bytes[chunk + i*4+2] << 8) | bytes[chunk + i*4+3];
    for (let i = 16; i < 64; i++) {
      const s0 = rotr(W[i-15], 7) ^ rotr(W[i-15], 18) ^ (W[i-15] >>> 3);
      const s1 = rotr(W[i-2], 17) ^ rotr(W[i-2], 19) ^ (W[i-2] >>> 10);
      W[i] = (W[i-16] + s0 + W[i-7] + s1) | 0;
    }
    let a=H[0], b=H[1], c=H[2], d=H[3], e=H[4], f=H[5], g=H[6], h=H[7];
    for (let i = 0; i < 64; i++) {
      const S1 = rotr(e, 6) ^ rotr(e, 11) ^ rotr(e, 25);
      const ch = (e & f) ^ (~e & g);
      const t1 = (h + S1 + ch + K[i] + W[i]) | 0;
      const S0 = rotr(a, 2) ^ rotr(a, 13) ^ rotr(a, 22);
      const mj = (a & b) ^ (a & c) ^ (b & c);
      const t2 = (S0 + mj) | 0;
      h=g; g=f; f=e; e=(d+t1)|0; d=c; c=b; b=a; a=(t1+t2)|0;
    }
    H[0]=(H[0]+a)|0; H[1]=(H[1]+b)|0; H[2]=(H[2]+c)|0; H[3]=(H[3]+d)|0;
    H[4]=(H[4]+e)|0; H[5]=(H[5]+f)|0; H[6]=(H[6]+g)|0; H[7]=(H[7]+h)|0;
  }
  return H.map(x => (x >>> 0).toString(16).padStart(8, '0')).join('');
}

// Phone Meta: dígitos puros sem + (E.164 do Google Ads tem +, Meta NÃO)
function normalizePhoneForMeta(raw) {
  let d = String(raw || '').replace(/\D/g, '').replace(/^0+/, '');
  if (!d) return '';
  if (d.length === 10 || d.length === 11) return '55' + d;
  return d;
}

// ====== INPUT — parse string body (sendBeacon força text/plain) ======
let input = $input.item.json.body || $input.item.json;
if (typeof input === 'string') {
  try { input = JSON.parse(input); } catch (e) { input = {}; }
}

// ====== ALLOWLIST GUARD (defense in depth, camada 3) ======
if (!ALLOWED_EVENTS.includes(input.event_name)) {
  return { json: { skipped: true, reason: 'event_name not in allowlist', event_name: input.event_name } };
}

const headers = $input.item.json.headers || {};
const ud = input.user_data || {};
const cd = input.custom_data || {};

// ====== HASH PII ======
const phoneMeta = normalizePhoneForMeta(ud.ph);

return {
  json: {
    pixel_id: PIXEL_ID,
    api_version: API_VERSION,
    test_event_code: TEST_EVENT_CODE,
    event_name: input.event_name,
    event_time: input.event_time || Math.floor(Date.now() / 1000),
    event_id: input.event_id,
    event_source_url: input.event_source_url,
    hashed_em: sha256(ud.em),
    hashed_ph: sha256(phoneMeta),
    hashed_fn: sha256(ud.fn),
    hashed_ln: sha256(ud.ln),
    hashed_ct: sha256(ud.ct),
    hashed_st: sha256(ud.st),
    hashed_country: sha256(ud.country),
    hashed_external_id: ud.external_id || ud.user_id || sha256(phoneMeta),
    fbc: ud.fbc || '',
    fbp: ud.fbp || '',
    user_ip: headers['x-forwarded-for'] ? headers['x-forwarded-for'].split(',')[0].trim() : (headers['x-real-ip'] || ''),
    // CRÍTICO: client_user_agent vem do FRONT (navigator.userAgent), NÃO do header N8N
    user_agent: ud.client_user_agent || headers['user-agent'] || '',
    custom_data: cd
  }
};

// Log estruturado da resposta do Meta (visível em Executions tab)
const response = $input.item.json;
const statusCode = response.statusCode || 0;
const body = response.body || {};

const log = {
  timestamp: new Date().toISOString(),
  meta_status: statusCode,
  meta_events_received: body.events_received || 0,
  meta_messages: body.messages || [],
  meta_fbtrace_id: body.fbtrace_id || null,
  meta_error: body.error || null,
  success: statusCode === 200 && (body.events_received || 0) > 0
};

if (!log.success) {
  console.error('Meta CAPI error:', JSON.stringify(log));
}

return { json: log };
